INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f5774d43-d43e-48f7-a6e7-dac578792e23',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jenkins to GitHub Actions — Pipelines, Shared Libraries, and Plugins Remapped$escape$,
  $escape$If you live in Jenkinsfile land, GitHub Actions has a 1-to-1 mental model — once you know the vocabulary. A workflow (.github/workflows/*.yml) is your Jenkinsfile. Jobs are your stages, but run in isolated VMs in parallel by default — no parallel {} block needed. Steps inside a job map directly to your sh or bat steps, plus uses: to pull a marketplace action (think plugins, but versioned via Git tags, not a plugin manager). Shared Libraries become reusable workflows: define a workflow in .github/workflows/build-template.yml with on: workflow_call:, then reference it with uses: org/repo/.github/workflows/build-template.yml@main. Inputs replace your library function parameters. One critical difference from Jenkins: there's no built-in agent inheritance. Each job declares its own runs-on, so you can't set a global agent at the pipeline level. Secrets from Jenkins credentials() become secrets.MY_SECRET, scoped per job or the whole workflow. Matrix builds that previously needed Jenkins plugins are native — just drop a matrix: block under strategy:.$escape$,
  $escape$# .github/workflows/ci.yml
name: CI
on: [push]
jobs:
  build:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4
      - uses: actions/setup-node@v4
        with:
          node-version: 20
      - run: npm ci && npm test

  deploy:
    needs: build
    uses: my-org/shared-workflows/.github/workflows/deploy.yml@main
    with:
      environment: staging
    secrets: inherit$escape$,
