INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2f20d8f3-708f-4a5a-bd93-7e7dc4fe12a5',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jenkins Dev's Field Guide to GitLab CI: Stages, Artifacts, and Shared Templates$escape$,
  $escape$Coming from Jenkins, GitLab CI's `.gitlab-ci.yml` feels familiar but has sharp differences worth knowing upfront. Stages in GitLab CI work like Jenkins `stages {}` blocks — jobs in the same stage run in parallel, stages run sequentially. Unlike Jenkins where `stash`/`unstash` moves files between stages, GitLab uses `artifacts: paths` to persist outputs and `dependencies` to pull them into downstream jobs explicitly. Cache is separate — it's for reusing slow-to-build directories like `node_modules` between pipelines, keyed by branch and a cache key. Runners replace Jenkins agents: you register a runner with a tag (e.g., `docker`, `k8s`), then target it via `tags:` in each job — no `agent { label '' }` syntax. The biggest power unlock is `include:` — GitLab's equivalent of Jenkins Shared Libraries. You can compose pipelines from reusable template files hosted in the same repo or a central project, pulling in `.gitlab-ci.yml` fragments with `include: project:` or `include: local:`. This replaces the ceremony of `@Library` declarations and `vars/` scripts entirely.$escape$,
  $escape$# .gitlab-ci.yml — annotated for Jenkins developers
stages: [build, test, deploy]

build-job:
  stage: build
  tags: [docker]          # like: agent { label 'docker' }
  script:
    - npm ci
    - npm run build
  artifacts:
    paths: [dist/]        # like: stash includes: 'dist/**'
    expire_in: 1 hour
  cache:
    key: $CI_COMMIT_REF_SLUG
    paths: [node_modules/]

include:
  - project: 'org/ci-templates'
    file: '/templates/deploy.yml'  # like: @Library('ci-templates')import deploy$escape$,
  $escape$bash$escape$,
