INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '895dbad4-76ab-4eee-ba28-b589a549af18',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jenkins Security Scanning — SAST, Dependency, and Container Checks in One Pipeline$escape$,
  $escape$Jenkins pipelines can integrate three distinct scanning layers using purpose-built plugins and CLI tools. For SAST, the Warnings Next Generation plugin (`recordIssues`) ingests reports from tools like Semgrep or SpotBugs — run them as a `sh` step and point `recordIssues` at the output file. Dependency scanning fits naturally in a `stage('SCA')` block using OWASP Dependency-Check plugin (`dependencyCheck` / `dependencyCheckPublisher`) — it downloads the NVD feed on first run and caches it in `$JENKINS_HOME`. Container scanning belongs after the `docker build` step; invoke Trivy via `sh 'trivy image --exit-code 1 --severity HIGH,CRITICAL myapp:${BUILD_NUMBER}'`. The `--exit-code 1` flag fails the build on policy violations. Gate the pipeline by wrapping all three stages in a `parallel` block to cut wall-clock time, then aggregate results in a downstream `post { always { ... } }` block. Store reports as artifacts with `archiveArtifacts` so the Jenkins UI surfaces findings without external dashboards.$escape$,
  $escape$pipeline {
  agent any
  stages {
    stage('Security') {
      parallel {
        stage('SAST') {
          steps {
            sh 'semgrep --config=auto --json > semgrep-report.json || true'
            recordIssues tools: [semgrep(pattern: 'semgrep-report.json')]
          }
        }
        stage('SCA') {
          steps {
            dependencyCheck additionalArguments: '--scan . --format JSON', odcInstallation: 'OWASP-DC'
            dependencyCheckPublisher pattern: '**/dependency-check-report.json'
          }
        }
        stage('Container') {
          steps {
            sh 'trivy image --exit-code 1 --severity HIGH,CRITICAL myapp:${BUILD_NUMBER}'
          }
        }
      }
    }
  }
  post {
    always {
      archiveArtifacts artifacts: '**/semgrep-report.json, **/dependency-check-report.json'
    }
  }
}$escape$,
  $escape$bash$escape$,
